 1→import supabase from "../services/supabase.js";
 2→import { asyncHandler } from "../utils/controllerHandler.js";
 3→import { isValidUuid } from "../utils/validation.js";
 4→
 5→export const getFollowsDataController = asyncHandler(async (req, res) => {
 6→    const { userId } = req.query;
 7→    const loggedInUserId = req.userId || null;
 8→
 9→    if (!userId || !isValidUuid(userId)) {
10→        return res.status(400).json({ error: 'valid userId is required' });
11→    }
12→
13→    const { data, error } = await supabase.rpc('get_follow_data', {
14→        p_user_id: userId,
15→        p_logged_in_user_id: (loggedInUserId && isValidUuid(loggedInUserId)) ? loggedInUserId : null,
16→    });
17→
18→    if (error) {
19→        console.error('get_follow_data rpc error:', error.message);
20→        return res.status(500).json({ error: 'failed to fetch data' });
21→    }
22→
23→    return res.status(200).json(data);
24→});
