121→export const getUserOpinionsController = asyncHandler(async (req, res) => {
122→    const { before, userId } = req.query;
123→    const parsedLimit = parseOpinionLimit(req.query.limit);
124→    if (parsedLimit == null) {
125→        return res.status(400).json({ error: 'limit should be number and not be greater than 20 or less than 1' });
126→    }
127→    if (!userId) {
128→        return res.status(400).json({ error: 'no user id available!' });
