  1→import supabase from "./supabase.js";
  2→import { AppError } from "../utils/AppError.js";
  3→
  4→export const likeService = async(journalId, receiverId, senderId) =>{
  5→    if(!journalId || !receiverId){
  6→        throw new AppError(400, 'journalId or receiverId is undefined');
  7→    }
  8→
  9→    if(!senderId){
 10→        throw new AppError(400, 'senderId is undefined');
 11→    }
 12→
 13→    const isOwnContent = senderId === receiverId;
 14→
 15→    const {data: existingLike, error: errorExistingLike} = await supabase
 16→    .from('likes')
 17→    .select('user_id')
 18→    .eq('user_id', senderId)
 19→    .eq('journal_id', journalId)
 20→    .maybeSingle()
 21→
 22→    if(errorExistingLike){
 23→        console.error('supabase error while checking existing like')
 24→    }
 25→
 26→    if(!existingLike){
 27→        const insertNotifPromise = supabase
 28→        .from('notifications')
 29→        .insert({
 30→            sender_id: senderId,
 31→            receiver_id: receiverId,
 32→            journal_id: journalId,
 33→            type: 'like',
 34→            read: false
 35→        })
 36→
 37→        const insertLikePromise = supabase
 38→        .from('likes')
 39→        .insert({
 40→            user_id: senderId,
 41→            journal_id: journalId,
 42→        })
 43→
 44→        const [insertNotif, insertLike ] = await Promise.all([
 45→            isOwnContent ? Promise.resolve({error: null}) : insertNotifPromise,
 46→            insertLikePromise
 47→        ])
 48→
 49→        const {error: errorInsertNotificationResult} = insertNotif;
 50→        const {error: errorInserLikeResult} = insertLike;
 51→
 52→        if(errorInsertNotificationResult || errorInserLikeResult){
 53→            console.error('supabase error:', errorInserLikeResult?.message || errorInsertNotificationResult?.message);
 54→            throw new AppError(500, 'supabase error while inserting likes');
 55→        }
 56→
 57→        return {message: 'liked'};
 58→    } else {
 59→        const deleteNotifPromise = supabase
 60→        .from('notifications')
 61→        .delete()
 62→        .eq('receiver_id', receiverId)
 63→        .eq('sender_id', senderId)
 64→        .eq('journal_id', journalId)
 65→        .eq('type', 'like')
 66→
 67→        const deleteLikePromise = await supabase
 68→        .from('likes')
 69→        .delete()
 70→        .eq('user_id', senderId)
 71→        .eq('journal_id', journalId)
 72→
 73→        const [deleteNotif, deleteLike] = await Promise.all([deleteNotifPromise, deleteLikePromise]);
 74→        const {error: errorDeleteNotif} = deleteNotif;
 75→        const {error: errorDeleteLike} = deleteLike;
 76→
 77→        if(errorDeleteNotif || errorDeleteLike){
 78→            console.error('supabase error while deleting like', errorDeleteLike?.message || errorDeleteNotif?.message);
 79→            throw new AppError(500, 'supabase error while deleting like');
 80→        }
 81→
 82→        return {message: 'unliked'};
 83→    }
 84→
 85→}
