108→export const getPostRepliesController = asyncHandler(async (req, res) => {
109→    const { parent_id } = req.params;
110→    const { limit, before } = req.query;
111→
112→    if (!parent_id) {
113→        return res.status(400).json({ error: 'parent_id is undefined' });
114→    }
115→
116→    const parsedLimit = parseInt(limit);
117→    if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20) {
118→        return res.status(400).json({ error: 'limit should be integer or it should be between 1 to 20' });
119→    }
120→
121→    let query = supabase
122→        .from('comments')
123→        .select(COMMENT_REPLY_SELECT)
124→        .eq('parent_id', parent_id)
125→        .order('id', { ascending: false })
126→        .limit(parsedLimit + 1);
127→
128→    if (before) query = query.lt('id', before);
129→
130→    const { data, error } = await query;
131→    if (error) {
132→        console.error('supabase error while fetching replies:', error.message);
133→        return res.status(500).json({ error: 'supabase error while getting post replies' });
134→    }
135→
136→    const hasMore = data.length > parsedLimit;
137→    const slicedData = hasMore ? data.slice(0, parsedLimit) : data;
138→    return res.status(200).json({ data: slicedData, hasMore });
139→});
