  1→import supabase from "./supabase.js";
  2→
  3→const VALID_REACTIONS = ['fire', 'heart', 'mind_blown', 'clap', 'laugh', 'sad'];
  4→
  5→/**
  6→ * Toggle a reaction on a post.
  7→ * - Same emoji = remove reaction
  8→ * - Different emoji = switch reaction
  9→ * - No existing = add reaction
 10→ */
 11→export const toggleReactionService = async (journalId, receiverId, senderId, reactionType) => {
 12→    if (!journalId || !senderId) {
 13→        throw { status: 400, error: 'journalId and senderId are required' };
 14→    }
 15→
 16→    if (!VALID_REACTIONS.includes(reactionType)) {
 17→        throw { status: 400, error: 'invalid reaction type' };
 18→    }
 19→
 20→    const isOwnContent = senderId === receiverId;
 21→
 22→    // Check existing reaction
 23→    const { data: existing, error: fetchErr } = await supabase
 24→        .from('reactions')
 25→        .select('id, reaction_type')
 26→        .eq('user_id', senderId)
 27→        .eq('journal_id', journalId)
 28→        .maybeSingle();
 29→
 30→    if (fetchErr) {
 31→        console.error('error checking existing reaction:', fetchErr.message);
 32→    }
 33→
 34→    if (!existing) {
 35→        // No existing reaction → insert new
 36→        const insertReactionPromise = supabase
 37→            .from('reactions')
 38→            .insert({
 39→                user_id: senderId,
 40→                journal_id: journalId,
 41→                reaction_type: reactionType,
 42→            });
 43→
 44→        const insertNotifPromise = supabase
 45→            .from('notifications')
 46→            .insert({
 47→                sender_id: senderId,
 48→                receiver_id: receiverId,
 49→                journal_id: journalId,
 50→                type: 'reaction',
 51→                reaction_type: reactionType,
 52→                read: false,
 53→            });
 54→
 55→        const [insertReaction, insertNotif] = await Promise.all([
 56→            insertReactionPromise,
 57→            isOwnContent ? Promise.resolve({ error: null }) : insertNotifPromise,
 58→        ]);
 59→
 60→        if (insertReaction.error) {
 61→            console.error('error inserting reaction:', insertReaction.error.message);
 62→            throw { status: 500, error: 'failed to add reaction' };
 63→        }
 64→        if (insertNotif?.error) {
 65→            console.error('error inserting reaction notification:', insertNotif.error.message);
 66→        }
 67→
 68→        return { message: 'reacted', reaction_type: reactionType };
 69→    }
 70→
 71→    if (existing.reaction_type === reactionType) {
 72→        // Same emoji → remove reaction
 73→        const deleteReactionPromise = supabase
 74→            .from('reactions')
 75→            .delete()
 76→            .eq('id', existing.id);
 77→
 78→        const deleteNotifPromise = supabase
 79→            .from('notifications')
 80→            .delete()
 81→            .eq('sender_id', senderId)
 82→            .eq('receiver_id', receiverId)
 83→            .eq('journal_id', journalId)
 84→            .eq('type', 'reaction');
 85→
 86→        const [deleteReaction, deleteNotif] = await Promise.all([
 87→            deleteReactionPromise,
 88→            deleteNotifPromise,
 89→        ]);
 90→
 91→        if (deleteReaction.error) {
 92→            console.error('error deleting reaction:', deleteReaction.error.message);
 93→            throw { status: 500, error: 'failed to remove reaction' };
 94→        }
 95→
 96→        return { message: 'unreacted', reaction_type: null };
 97→    }
 98→
 99→    // Different emoji → switch reaction
100→    const updateReactionPromise = supabase
101→        .from('reactions')
102→        .update({ reaction_type: reactionType })
103→        .eq('id', existing.id);
104→
105→    // Update notification too
106→    const updateNotifPromise = supabase
107→        .from('notifications')
108→        .update({ reaction_type: reactionType })
109→        .eq('sender_id', senderId)
110→        .eq('receiver_id', receiverId)
111→        .eq('journal_id', journalId)
112→        .eq('type', 'reaction');
113→
114→    const [updateReaction] = await Promise.all([
115→        updateReactionPromise,
116→        isOwnContent ? Promise.resolve({ error: null }) : updateNotifPromise,
117→    ]);
118→
119→    if (updateReaction.error) {
120→        console.error('error updating reaction:', updateReaction.error.message);
121→        throw { status: 500, error: 'failed to switch reaction' };
122→    }
123→
124→    return { message: 'switched', reaction_type: reactionType };
125→};
