 28→const DashboardBriefing = ({ onWriteResponse }) => {
 29→    const { session, user } = useAuth();
 30→    const weekKey = getWeekKey();
 31→
 32→    const [recapCollapsed, setRecapCollapsed] = useState(() => {
 33→        try { return localStorage.getItem(weekKey) === 'true'; }
 34→        catch { return false; }
 35→    });
 36→
 37→    // ─── Data fetching ───
 38→
 39→    const { data: recapData, isLoading: recapLoading } = useQuery({
 40→        queryKey: ['weeklyRecap', session?.user?.id],
 41→        queryFn: () => getWeeklyRecap(session?.access_token),
 42→        enabled: !!session?.access_token,
 43→        staleTime: 1000 * 60 * 10,
 44→        refetchOnWindowFocus: false,
 45→    });
 46→
 47→    const { data: prompt, isLoading: promptLoading } = useQuery({
 48→        queryKey: ['todaysPrompt'],
 49→        queryFn: getTodaysPrompt,
 50→        staleTime: 1000 * 60 * 30,
 51→        refetchOnWindowFocus: false,
 52→    });
 53→
 54→    const { data: responsesData } = useQuery({
 55→        queryKey: ['promptResponses', prompt?.id],
 56→        queryFn: () => getPromptResponses(prompt.id),
 57→        enabled: !!prompt?.id,
 58→        staleTime: 1000 * 60 * 5,
 59→        refetchOnWindowFocus: false,
 60→    });
 61→
 62→    const { data: streakData } = useStreakData(user?.id);
 63→
 64→    // ─── Derived state ───
 65→
 66→    const recap = recapData?.recap;
 67→    const personal = recap?.personal || {};
 68→    const group = recap?.group || {};
 69→
 70→    const hasRecap = !recapLoading && recap &&
 71→        (personal.posts_written > 0 || group.total_posts > 0);
 72→    const hasPrompt = !promptLoading && !!prompt;
 73→
 74→    // Nothing to show
 75→    if (!hasRecap && !hasPrompt) return null;
 76→
 77→    const handleToggleRecap = (e) => {
 78→        e.stopPropagation();
 79→        const next = !recapCollapsed;
 80→        try { localStorage.setItem(weekKey, next ? 'true' : 'false'); }
 81→        catch { /* no-op */ }
 82→        setRecapCollapsed(next);
 83→    };
 84→
 85→    const streakCount = streakData?.current_streak || 0;
 86→
 87→    return (
 88→        <AnimatePresence>
 89→            <motion.div
 90→                className="dashboard-briefing"
 91→                initial={{ opacity: 0 }}
 92→                animate={{ opacity: 1 }}
